9: // applyFrontendDefaults applies all DashboardModel constructor defaults
10: func applyFrontendDefaults(dashboard map[string]interface{}) {
11: 	// DashboardModel constructor defaults - only set defaults that the frontend actually sets
12: 	if dashboard["title"] == nil {
13: 		dashboard["title"] = "No Title"
14: 	}
15: 	if dashboard["tags"] == nil {
16: 		dashboard["tags"] = []interface{}{}
17: 	}
18: 	if dashboard["timezone"] == nil {
19: 		dashboard["timezone"] = ""
20: 	}
21: 	if dashboard["weekStart"] == nil {
22: 		dashboard["weekStart"] = ""
23: 	}
24: 	if dashboard["editable"] == nil {
25: 		dashboard["editable"] = true
26: 	}
27: 	if dashboard["graphTooltip"] == nil {
28: 		dashboard["graphTooltip"] = float64(0)
29: 	}
30: 	if dashboard["time"] == nil {
31: 		dashboard["time"] = map[string]interface{}{
32: 			"from": "now-6h",
33: 			"to":   "now",
34: 		}
35: 	}
36: 	if dashboard["timepicker"] == nil {
